#nullable enable // autogenerated

using System.Linq;
using MVZ2.GameContent.Damages;
using MVZ2.Vanilla.Callbacks;
using MVZ2Logic.Artifacts;
using MVZ2Logic.Definitions;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Callbacks;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Artifacts
{
    [AutoArtifactDefinition(VanillaArtifactNames.PbCore)]
    public class PbCore : ArtifactDefinition
    {
        public PbCore(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(VanillaLevelCallbacks.PRE_ENTITY_TAKE_DAMAGE, PreEntityTakeDamageCallback, priority: VanillaCallbackPriorities.MULTIPLY);
        }
        public override void PostUpdate(Artifact artifact)
        {
            base.PostUpdate(artifact);
            artifact.SetGlowing(true);
        }
        private void PreEntityTakeDamageCallback(VanillaLevelCallbacks.PreTakeDamageParams param, CallbackResult result)
        {
            var input = param.input;
            if (!input.HasEffect(VanillaDamageEffects.RADIATION))
                return;
            var entity = input.Entity;
            if (!(entity.Type == EntityTypes.PLANT && entity.IsFriendlyEntity()))
                return;
            var count = entity.Level.GetArtifacts().Count(a => a != null && a.Definition == this);
            input.Multiply(1 - DAMAGE_MULTIPLIER_ADDITION * count);
        }
        public const float DAMAGE_MULTIPLIER_ADDITION = 0.8f;
    }
}
